import azure.functions as func
import logging
import json
import os
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent
from datetime import datetime
import uuid

app = func.FunctionApp()

# Configuration
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<storage-account>.blob.core.windows.net")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<cosmos-account>.documents.azure.com:443/")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "ProcessedData")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "Results")
EVENT_GRID_ENDPOINT = os.environ.get("EVENT_GRID_ENDPOINT", "https://<topic-name>.<region>.eventgrid.azure.net/api/events")

# Initialize clients with Managed Identity
credential = DefaultAzureCredential()
blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(EVENT_GRID_ENDPOINT, credential)

# Get Cosmos DB database and container
database = cosmos_client.get_database_client(COSMOS_DATABASE_NAME)
container = database.get_container_client(COSMOS_CONTAINER_NAME)


@app.blob_trigger(arg_name="myblob", path="input-files/{name}",
                  connection="STORAGE_ACCOUNT_URL")
def process_blob_file(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}, Size: {myblob.length} bytes")
    
    try:
        # Read blob content
        blob_content = myblob.read()
        
        # Process the file (example: count lines if text file)
        try:
            content_str = blob_content.decode('utf-8')
            lines = content_str.split('\n')
            line_count = len(lines)
            word_count = sum(len(line.split()) for line in lines)
            char_count = len(content_str)
        except UnicodeDecodeError:
            # Binary file
            line_count = 0
            word_count = 0
            char_count = len(blob_content)
        
        # Prepare result document
        result_id = str(uuid.uuid4())
        result_document = {
            "id": result_id,
            "blob_name": myblob.name,
            "blob_size": myblob.length,
            "line_count": line_count,
            "word_count": word_count,
            "char_count": char_count,
            "processed_at": datetime.utcnow().isoformat(),
            "status": "completed"
        }
        
        # Write to Cosmos DB
        container.create_item(body=result_document)
        logging.info(f"Successfully wrote result to Cosmos DB with ID: {result_id}")
        
        # Send notification via Event Grid
        event = CloudEvent(
            type="BlobProcessing.Completed",
            source=f"/blobstorage/{myblob.name}",
            data={
                "result_id": result_id,
                "blob_name": myblob.name,
                "blob_size": myblob.length,
                "line_count": line_count,
                "word_count": word_count,
                "processed_at": result_document["processed_at"]
            },
            subject=f"processing/{myblob.name}"
        )
        
        event_grid_client.send([event])
        logging.info(f"Successfully sent Event Grid notification for blob: {myblob.name}")
        
        # Optionally move processed file to archive container
        archive_processed_blob(myblob.name, blob_content)
        
    except Exception as e:
        logging.error(f"Error processing blob {myblob.name}: {str(e)}")
        
        # Write error to Cosmos DB
        error_document = {
            "id": str(uuid.uuid4()),
            "blob_name": myblob.name,
            "blob_size": myblob.length,
            "error_message": str(e),
            "processed_at": datetime.utcnow().isoformat(),
            "status": "failed"
        }
        
        try:
            container.create_item(body=error_document)
        except Exception as cosmos_error:
            logging.error(f"Failed to write error to Cosmos DB: {str(cosmos_error)}")
        
        # Send error notification
        try:
            error_event = CloudEvent(
                type="BlobProcessing.Failed",
                source=f"/blobstorage/{myblob.name}",
                data={
                    "blob_name": myblob.name,
                    "error_message": str(e),
                    "processed_at": error_document["processed_at"]
                },
                subject=f"processing/error/{myblob.name}"
            )
            event_grid_client.send([error_event])
        except Exception as eg_error:
            logging.error(f"Failed to send error notification: {str(eg_error)}")
        
        raise


def archive_processed_blob(blob_name: str, content: bytes):
    try:
        # Extract container and blob path
        parts = blob_name.split('/', 1)
        if len(parts) > 1:
            blob_path = parts[1]
        else:
            blob_path = blob_name
        
        # Upload to archive container
        archive_container_client = blob_service_client.get_container_client("processed-files")
        
        # Create container if it doesn't exist
        try:
            archive_container_client.create_container()
        except Exception:
            pass  # Container already exists
        
        archive_blob_name = f"{datetime.utcnow().strftime('%Y/%m/%d')}/{blob_path}"
        archive_blob_client = archive_container_client.get_blob_client(archive_blob_name)
        archive_blob_client.upload_blob(content, overwrite=True)
        
        logging.info(f"Archived blob to: {archive_blob_name}")
    except Exception as e:
        logging.warning(f"Failed to archive blob {blob_name}: {str(e)}")


@app.route(route="health", methods=["GET"])
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Health check endpoint called')
    
    health_status = {
        "status": "healthy",
        "timestamp": datetime.utcnow().isoformat(),
        "services": {}
    }
    
    # Check Blob Storage
    try:
        blob_service_client.get_account_information()
        health_status["services"]["blob_storage"] = "connected"
    except Exception as e:
        health_status["services"]["blob_storage"] = f"error: {str(e)}"
        health_status["status"] = "degraded"
    
    # Check Cosmos DB
    try:
        database.read()
        health_status["services"]["cosmos_db"] = "connected"
    except Exception as e:
        health_status["services"]["cosmos_db"] = f"error: {str(e)}"
        health_status["status"] = "degraded"
    
    return func.HttpResponse(
        json.dumps(health_status),
        mimetype="application/json",
        status_code=200 if health_status["status"] == "healthy" else 503
    )


@app.route(route="results/{result_id}", methods=["GET"])
def get_result(req: func.HttpRequest) -> func.HttpResponse:
    result_id = req.route_params.get('result_id')
    
    try:
        item = container.read_item(item=result_id, partition_key=result_id)
        return func.HttpResponse(
            json.dumps(item),
            mimetype="application/json",
            status_code=200
        )
    except Exception as e:
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            mimetype="application/json",
            status_code=404
        )


@app.route(route="results", methods=["GET"])
def list_results(req: func.HttpRequest) -> func.HttpResponse:
    try:
        limit = int(req.params.get('limit', 100))
        
        query = "SELECT * FROM c ORDER BY c.processed_at DESC"
        items = list(container.query_items(
            query=query,
            enable_cross_partition_query=True,
            max_item_count=limit
        ))
        
        return func.HttpResponse(
            json.dumps(items),
            mimetype="application/json",
            status_code=200
        )
    except Exception as e:
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            mimetype="application/json",
            status_code=500
        )